class Solution:
	def solve(self, coins, sum_):
		if sum_ == 0:
			return 0
		min_coins = float('inf')
		for coin in coins:
			if sum_ - coin >= 0:
				min_coins = min(min_coins, 1 + self.solve(coins, sum_ - coin))
		return min_coins if min_coins != float('inf') else -1

