#include <iostream>
#include <vector>
#include <limits>
using namespace std;

class Solution {
public:
	int solve(std::vector<int>& coins, int sum) {
		if (sum == 0) return 0;
		int min_coins = numeric_limits<int>::max();
		for (int coin = 0; coin < coins.size(); coin++) {
			if (sum - coins[coin] >= 0) {
				min_coins = min(min_coins, 1 + solve(coins, sum - coins[coin]));
			}
		}
		return min_coins == numeric_limits<int>::max() ? -1 : min_coins;
	}
};

int main() {
	int n;
	cin >> n;
	vector<int> coins(n);
	for (int i = 0; i < n; i++)
		cin >> coins[i];
	int sum;
	cin >> sum;
	Solution solution;
	cout << solution.solve(coins, sum) << endl;
	return 0;
}
